import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { PlayerProvider } from './context/PlayerContext';
import { AuthProvider } from './context/AuthContext'; // Import AuthProvider
import Navbar from './components/Navbar'; // Import Navbar mới
import Home from './pages/Home';
import Player from './components/Player';
import Upload from './pages/Upload';
import Login from './pages/Login';
import Register from './pages/Register';
import Profile from './pages/Profile'; // Import Profile
import SongDetail from './pages/SongDetail'; // Import trang mới

function App() {
  return (
    <AuthProvider>
      <PlayerProvider>
        {/* Thêm dòng future này để tắt cảnh báo v7 */}
        <Router future={{ v7_startTransition: true, v7_relativeSplatPath: true }}>
          <div className="App font-sans text-gray-900 bg-gray-100 min-h-screen">
            <Navbar />
            <Routes>
              <Route path="/" element={<Home />} />
              <Route path="/upload" element={<Upload />} />
              <Route path="/login" element={<Login />} />
              <Route path="/register" element={<Register />} />
              <Route path="/profile" element={<Profile />} /> {/* Thêm Route này */}
              <Route path="/song/:id" element={<SongDetail />} /> {/* Thêm Route này */}
            </Routes>
            <Player />
          </div>
        </Router>
      </PlayerProvider>
    </AuthProvider>
  );
}

export default App;
